This is extremely dangerous with vulnerable versions of lodash. The `_.merge()` function in lodash versions before 4.17.19 is vulnerable to Prototype Pollution (CVE-2020-8203), allowing attackers to inject properties into Object.prototype that affect ALL objects in your application.

**VULNERABLE CODE**:

```javascript
const _ = require('lodash'); // Vulnerable: lodash < 4.17.19
const express = require('express');
const app = express();

app.use(express.json());

// Default application configuration
const defaultConfig = {
  theme: 'light',
  notifications: true,
  language: 'en'
};

// Vulnerable: Deep merge with user-controlled input
app.post('/api/settings', (req, res) => {
  const userSettings = req.body;

  // DANGEROUS: Merging untrusted input directly
  const mergedConfig = _.merge({}, defaultConfig, userSettings);

  // Save to user session
  req.session.config = mergedConfig;

  res.json({ success: true, config: mergedConfig });
});

// Admin check that can be bypassed
app.get('/api/admin', (req, res) => {
  const user = req.session.user || {};

  // This check can be bypassed via prototype pollution!
  if (user.isAdmin) {
    res.json({ secret: 'admin-data-here' });
  } else {
    res.status(403).json({ error: 'Access denied' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```json
{
  "__proto__": {
    "isAdmin": true
  }
}
```

**Why This Is Dangerous**:
- The `__proto__` property pollutes `Object.prototype`, affecting ALL objects created afterward
- Every new object `{}` will now have `isAdmin: true` by default
- Authentication/authorization checks fail because they check properties that now exist on all objects
- In Node.js, this can lead to Remote Code Execution through polluted child_process options
- The vulnerability persists until the application restarts

**SECURE VERSION**:

```javascript
const _ = require('lodash'); // Must be >= 4.17.19
const express = require('express');
const Ajv = require('ajv');
const app = express();

app.use(express.json());

const ajv = new Ajv({ allowUnionTypes: true });

// Define strict schema for user settings
const settingsSchema = {
  type: 'object',
  properties: {
    theme: { type: 'string', enum: ['light', 'dark', 'system'] },
    notifications: { type: 'boolean' },
    language: { type: 'string', pattern: '^[a-z]{2}(-[A-Z]{2})?$' }
  },
  additionalProperties: false,  // CRITICAL: Reject unknown properties
  required: []
};

const validateSettings = ajv.compile(settingsSchema);

// Sanitize input to remove prototype pollution vectors
function sanitizeInput(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  const sanitized = Array.isArray(obj) ? [] : Object.create(null);

  for (const key of Object.keys(obj)) {
    // Block prototype pollution vectors
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      continue;
    }
    sanitized[key] = sanitizeInput(obj[key]);
  }

  return sanitized;
}

const defaultConfig = Object.freeze({
  theme: 'light',
  notifications: true,
  language: 'en'
});

app.post('/api/settings', (req, res) => {
  // Step 1: Sanitize input
  const sanitizedInput = sanitizeInput(req.body);

  // Step 2: Validate against schema
  if (!validateSettings(sanitizedInput)) {
    return res.status(400).json({ 
      error: 'Invalid settings',
      details: validateSettings.errors 
    });
  }

  // Step 3: Safe merge with sanitized, validated input
  const mergedConfig = { ...defaultConfig, ...sanitizedInput };

  req.session.config = mergedConfig;
  res.json({ success: true, config: mergedConfig });
});

app.listen(3000);
```

**Key Security Controls**:
- **Schema Validation with additionalProperties: false**: Rejects any properties not explicitly defined in the schema, blocking `__proto__` and other unexpected keys
- **Input Sanitization**: Explicitly filters out `__proto__`, `constructor`, and `prototype` keys before any processing
- **Updated Dependencies**: Using lodash >= 4.17.19 which has built-in prototype pollution protection
- **Object.freeze()**: Prevents modification of default configuration objects

Excellent question! Dependency security requires continuous monitoring, not just one-time fixes. Here's a comprehensive production-grade approach combining multiple tools and strategies.

**PRODUCTION PATTERN**:

```javascript
// package.json - Security-focused configuration
{
  "name": "secure-app",
  "version": "1.0.0",
  "scripts": {
    "audit": "npm audit --audit-level=moderate",
    "audit:fix": "npm audit fix",
    "audit:ci": "npm audit --audit-level=high --json > audit-report.json",
    "outdated": "npm outdated",
    "check-deps": "npx depcheck",
    "snyk-test": "snyk test --severity-threshold=high",
    "snyk-monitor": "snyk monitor",
    "preinstall": "npx npm-force-resolutions",
