Excellent question! Application-wide prototype pollution protection requires defense in depth: freezing prototypes, middleware sanitization, dependency auditing, and runtime monitoring.

**PRODUCTION PATTERN**:

```javascript
// security/prototype-freeze.js - Load FIRST in application
'use strict';

// Freeze Object.prototype to prevent pollution
// CAUTION: Do this early, before loading other modules
if (process.env.NODE_ENV === 'production') {
  Object.freeze(Object.prototype);
  Object.freeze(Array.prototype);
  Object.freeze(Function.prototype);
  console.log('[Security] Prototypes frozen');
}

// security/sanitization-middleware.js
const DANGEROUS_KEYS = new Set([
  '__proto__',
  'constructor',
  'prototype',
  '__defineGetter__',
  '__defineSetter__',
  '__lookupGetter__',
  '__lookupSetter__'
]);

function deepSanitize(obj, depth = 0, maxDepth = 10) {
  if (depth > maxDepth) {
    throw new Error('Object nesting too deep');
  }

  if (typeof obj !== 'object' || obj === null) {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => deepSanitize(item, depth + 1, maxDepth));
  }

  const sanitized = Object.create(null); // No prototype!

  for (const [key, value] of Object.entries(obj)) {
    // Block dangerous keys
    if (DANGEROUS_KEYS.has(key)) {
      console.warn(`[Security] Blocked dangerous key: ${key}`);
      continue;
    }

    // Block keys starting with underscore (common pollution vectors)
    if (key.startsWith('__')) {
      console.warn(`[Security] Blocked suspicious key: ${key}`);
      continue;
    }

    sanitized[key] = deepSanitize(value, depth + 1, maxDepth);
  }

  return sanitized;
}

function prototypePollutionMiddleware(req, res, next) {
  try {
    if (req.body && typeof req.body === 'object') {
      req.body = deepSanitize(req.body);
    }
    if (req.query && typeof req.query === 'object') {
      req.query = deepSanitize(req.query);
    }
    next();
  } catch (error) {
    console.error('[Security] Sanitization failed:', error.message);
    res.status(400).json({ error: 'Invalid request data' });
  }
}

module.exports = { deepSanitize, prototypePollutionMiddleware };
```

