// security/pollution-monitor.js
function monitorPrototypePollution() {
  const originalDefineProperty = Object.defineProperty;

  Object.defineProperty = function(obj, prop, descriptor) {
    // Detect attempts to modify prototypes
    if (obj === Object.prototype || 
        obj === Array.prototype || 
        obj === Function.prototype) {
      console.error(`[SECURITY ALERT] Prototype modification attempt: ${prop}`);

      // Send to monitoring system
      if (process.env.SENTRY_DSN) {
        const Sentry = require('@sentry/node');
        Sentry.captureMessage(`Prototype pollution attempt: ${prop}`, 'warning');
      }

      // In production, block the modification
      if (process.env.NODE_ENV === 'production') {
        throw new Error('Prototype modification blocked');
      }
    }

    return originalDefineProperty.call(this, obj, prop, descriptor);
  };
}

module.exports = { monitorPrototypePollution };
```

```javascript
// security/safe-merge.js - Safe object merging utilities
function safeMerge(target, ...sources) {
  // Create object with null prototype to avoid pollution
  const result = Object.create(null);

  // Copy target properties
  for (const key of Object.keys(target)) {
    if (!key.startsWith('__')) {
      result[key] = target[key];
    }
  }

  // Merge sources
  for (const source of sources) {
    if (typeof source !== 'object' || source === null) continue;

    for (const key of Object.keys(source)) {
      if (key.startsWith('__') || key === 'constructor') continue;

      if (typeof source[key] === 'object' && source[key] !== null &&
          typeof result[key] === 'object' && result[key] !== null) {
        result[key] = safeMerge(result[key], source[key]);
      } else {
        result[key] = source[key];
      }
    }
  }

  return result;
}

module.exports = { safeMerge };
