// scripts/audit-dependencies.js - Run in CI/CD pipeline
const { execSync } = require('child_process');
const fs = require('fs');

const BLOCKED_PACKAGES = [
  { name: 'lodash', maxVersion: '4.17.20' }, // Require 4.17.21+
  { name: 'minimist', maxVersion: '1.2.5' },
  { name: 'flat', maxVersion: '5.0.1' }
];

function auditDependencies() {
  console.log('Running npm audit...');

  try {
    const auditResult = execSync('npm audit --json', { encoding: 'utf8' });
    const audit = JSON.parse(auditResult);

    if (audit.metadata.vulnerabilities.critical > 0 ||
        audit.metadata.vulnerabilities.high > 0) {
      console.error('CRITICAL/HIGH vulnerabilities found!');
      process.exit(1);
    }
  } catch (error) {
    console.error('Audit failed:', error.message);
    process.exit(1);
  }

  // Check for known vulnerable versions
  const packageLock = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));

  for (const blocked of BLOCKED_PACKAGES) {
    const pkg = packageLock.dependencies?.[blocked.name];
    if (pkg && pkg.version <= blocked.maxVersion) {
      console.error(`Vulnerable ${blocked.name}@${pkg.version} detected!`);
      process.exit(1);
    }
  }

  console.log('Dependency audit passed!');
}

auditDependencies();
```

**Defense in Depth Layers**:
1. **Prototype freezing**: Freeze Object/Array/Function prototypes at startup to prevent modification
2. **Input sanitization middleware**: Strip dangerous keys from all incoming JSON before routes process them
3. **Runtime monitoring**: Intercept Object.defineProperty to detect pollution attempts
4. **Safe merge utilities**: Use custom merge functions that create null-prototype objects
5. **Dependency auditing**: Block known vulnerable package versions in CI/CD

**Additional Protections**:
- Use `Object.create(null)` for configuration objects to avoid prototype chain
- Enable strict mode (`'use strict'`) in all modules
- Use `Object.hasOwn()` instead of `hasOwnProperty()` to avoid prototype confusion
- Implement Content Security Policy headers to mitigate exploitation via XSS
- Run `npm audit` in CI/CD and fail builds on critical vulnerabilities
- Use tools like Snyk or Socket.dev for real-time dependency monitoring

