// DependencySecurityConfig.java - Runtime security controls
package com.enterprise.security;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.yaml.snakeyaml.LoaderOptions;
import org.yaml.snakeyaml.Yaml;
import org.yaml.snakeyaml.constructor.SafeConstructor;

@Configuration
public class DependencySecurityConfig {

    // HARDENED JACKSON: Prevent deserialization attacks
    @Bean
    public ObjectMapper secureObjectMapper() {
        ObjectMapper mapper = new ObjectMapper();

        // Disable dangerous features
        mapper.disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES);
        mapper.disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);

        // Enable polymorphic type validation (blocks gadget chains)
        BasicPolymorphicTypeValidator ptv = BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType("com.enterprise.")
            .denyForExactBaseType(Object.class)
            .build();
        mapper.activateDefaultTyping(ptv, ObjectMapper.DefaultTyping.NON_FINAL);

        return mapper;
    }

    // HARDENED SNAKEYAML: Prevent CVE-2022-1471 RCE
    @Bean
    public Yaml secureYaml() {
        LoaderOptions loaderOptions = new LoaderOptions();
        loaderOptions.setCodePointLimit(10 * 1024 * 1024); // 10MB limit
        loaderOptions.setMaxAliasesForCollections(50);
        loaderOptions.setNestingDepthLimit(50);

        // SafeConstructor prevents arbitrary object instantiation
        return new Yaml(new SafeConstructor(loaderOptions));
    }
}
