// DependencyHealthIndicator.java - Runtime monitoring
package com.enterprise.security;

import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.stereotype.Component;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.InputStream;
import java.util.Properties;

@Component
public class DependencyHealthIndicator implements HealthIndicator {

    private static final Logger logger = LoggerFactory.getLogger(DependencyHealthIndicator.class);
    private static final String LOG4J_SAFE_VERSION = "2.17.0";

    @Override
    public Health health() {
        try {
            // Check for vulnerable Log4j at runtime
            String log4jVersion = getLog4jVersion();
            if (log4jVersion != null && isVulnerableVersion(log4jVersion)) {
                logger.error("SECURITY ALERT: Vulnerable Log4j version detected: {}", log4jVersion);
                return Health.down()
                    .withDetail("log4j.version", log4jVersion)
                    .withDetail("vulnerability", "CVE-2021-44228")
                    .withDetail("action", "IMMEDIATE_REMEDIATION_REQUIRED")
                    .build();
            }

            return Health.up()
                .withDetail("log4j.version", log4jVersion != null ? log4jVersion : "not present")
                .withDetail("status", "No known vulnerable dependencies")
                .build();

        } catch (Exception e) {
            logger.warn("Unable to verify dependency health: {}", e.getMessage());
            return Health.unknown().withException(e).build();
        }
    }

    private String getLog4jVersion() {
        try (InputStream is = getClass().getResourceAsStream(
                "/META-INF/maven/org.apache.logging.log4j/log4j-core/pom.properties")) {
            if (is != null) {
                Properties props = new Properties();
                props.load(is);
                return props.getProperty("version");
            }
        } catch (Exception e) {
            logger.debug("Log4j not present or version unreadable");
        }
        return null;
    }

    private boolean isVulnerableVersion(String version) {
        // Vulnerable: 2.0-beta9 to 2.17.0 (exclusive)
        return version.startsWith("2.") && 
               version.compareTo(LOG4J_SAFE_VERSION) < 0;
    }
}
