For production Go applications, you need automated vulnerability scanning, dependency pinning, SBOM generation, and continuous monitoring. Here's a comprehensive approach:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/exec"
	"strings"
	"time"
)

// DependencyScanner handles vulnerability scanning
type DependencyScanner struct {
	logger       *log.Logger
	alertWebhook string
	modulePath   string
}

type VulnerabilityReport struct {
	Module        string    `json:"module"`
	Version       string    `json:"version"`
	Vulnerability string    `json:"vulnerability"`
	Severity      string    `json:"severity"`
	FixedVersion  string    `json:"fixed_version"`
	ScannedAt     time.Time `json:"scanned_at"`
}

type ScanResult struct {
	Vulnerabilities []VulnerabilityReport `json:"vulnerabilities"`
	TotalCount      int                   `json:"total_count"`
	CriticalCount   int                   `json:"critical_count"`
	HighCount       int                   `json:"high_count"`
	ScanDuration    time.Duration         `json:"scan_duration"`
}

func NewDependencyScanner(modulePath, alertWebhook string) *DependencyScanner {
	return &DependencyScanner{
		logger:       log.New(os.Stdout, "[DEP-SCAN] ", log.LstdFlags|log.Lshortfile),
		alertWebhook: alertWebhook,
		modulePath:   modulePath,
	}
}

// RunGoVulnCheck executes govulncheck for vulnerability scanning
func (ds *DependencyScanner) RunGoVulnCheck(ctx context.Context) (*ScanResult, error) {
	start := time.Now()
	ds.logger.Printf("Starting vulnerability scan for %s", ds.modulePath)

	// Run govulncheck - Go's official vulnerability scanner
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = ds.modulePath

	output, err := cmd.CombinedOutput()
	if err != nil {
		// govulncheck returns non-zero if vulnerabilities found
		ds.logger.Printf("Scan completed with findings: %v", err)
	}

	result := &ScanResult{
		Vulnerabilities: make([]VulnerabilityReport, 0),
		ScanDuration:    time.Since(start),
	}

	// Parse JSON output from govulncheck
	if err := ds.parseGovulncheckOutput(output, result); err != nil {
		return nil, fmt.Errorf("failed to parse scan output: %w", err)
	}

	// Count by severity
	for _, vuln := range result.Vulnerabilities {
		switch strings.ToUpper(vuln.Severity) {
		case "CRITICAL":
			result.CriticalCount++
		case "HIGH":
			result.HighCount++
		}
	}
	result.TotalCount = len(result.Vulnerabilities)

	ds.logger.Printf("Scan complete: %d total, %d critical, %d high vulnerabilities",
		result.TotalCount, result.CriticalCount, result.HighCount)

	return result, nil
}

func (ds *DependencyScanner) parseGovulncheckOutput(output []byte, result *ScanResult) error {
	// Simplified parsing - real implementation would handle govulncheck JSON format
	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(line, "Vulnerability") {
			result.Vulnerabilities = append(result.Vulnerabilities, VulnerabilityReport{
				ScannedAt: time.Now(),
			})
		}
	}
	return nil
}

// AlertOnCritical sends alerts for critical vulnerabilities
func (ds *DependencyScanner) AlertOnCritical(ctx context.Context, result *ScanResult) error {
	if result.CriticalCount == 0 && result.HighCount == 0 {
		return nil
	}

	alert := map[string]interface{}{
		"text":     fmt.Sprintf("🚨 Security Alert: %d critical, %d high vulnerabilities found", result.CriticalCount, result.HighCount),
		"severity": "critical",
		"findings": result.Vulnerabilities,
	}

	jsonData, _ := json.Marshal(alert)

	req, err := http.NewRequestWithContext(ctx, "POST", ds.alertWebhook, strings.NewReader(string(jsonData)))
	if err != nil {
		return err
	}
	req.Header.Set("Content-Type", "application/json")

	client := &http.Client{Timeout: 10 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("failed to send alert: %w", err)
	}
	defer resp.Body.Close()

	ds.logger.Printf("Alert sent successfully")
	return nil
}

// VerifyGoSum checks go.sum integrity
func (ds *DependencyScanner) VerifyGoSum(ctx context.Context) error {
	ds.logger.Println("Verifying go.sum integrity...")

	cmd := exec.CommandContext(ctx, "go", "mod", "verify")
	cmd.Dir = ds.modulePath

	if output, err := cmd.CombinedOutput(); err != nil {
		return fmt.Errorf("go.sum verification failed: %s - %w", string(output), err)
	}

	ds.logger.Println("go.sum verification passed")
	return nil
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
	defer cancel()

	scanner := NewDependencyScanner(
		os.Getenv("MODULE_PATH"),
		os.Getenv("ALERT_WEBHOOK"),
	)

	// Verify dependency integrity first
	if err := scanner.VerifyGoSum(ctx); err != nil {
		log.Fatalf("Dependency verification failed: %v", err)
	}

	// Run vulnerability scan
	result, err := scanner.RunGoVulnCheck(ctx)
	if err != nil {
		log.Fatalf("Scan failed: %v", err)
	}

	// Alert on critical findings
	if err := scanner.AlertOnCritical(ctx, result); err != nil {
		log.Printf("Failed to send alert: %v", err)
	}

	// Fail CI/CD if critical vulnerabilities found
	if result.CriticalCount > 0 {
		os.Exit(1)
	}
}
