/*
{
    "require": {
        "phpmailer/phpmailer": "^6.8",
        "guzzlehttp/guzzle": "^7.8",
        "symfony/http-foundation": "^6.4",
        "monolog/monolog": "^3.5"
    },
    "require-dev": {
        "roave/security-advisories": "dev-latest"
    },
    "config": {
        "allow-plugins": {
            "roave/security-advisories": true
        }
    }
}
*/

require 'vendor/autoload.php';

use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\SMTP;
use PHPMailer\PHPMailer\Exception;

class SecureContactForm {
    private PHPMailer $mail;
    private array $allowedDomains = ['gmail.com', 'yahoo.com', 'outlook.com'];

    public function __construct() {
        $this->mail = new PHPMailer(true);
        // Use SMTP instead of mail() function
        $this->mail->isSMTP();
        $this->mail->Host = getenv('SMTP_HOST');
        $this->mail->SMTPAuth = true;
        $this->mail->Username = getenv('SMTP_USER');
        $this->mail->Password = getenv('SMTP_PASS');
        $this->mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
        $this->mail->Port = 587;
    }

    public function sendMessage(string $name, string $email, string $message): bool {
        // Validate and sanitize email strictly
        if (!$this->validateEmail($email)) {
            throw new InvalidArgumentException('Invalid email address');
        }

        // Sanitize name - remove any shell metacharacters
        $safeName = preg_replace('/[^a-zA-Z0-9\s]/', '', $name);
        $safeName = substr($safeName, 0, 50);

        try {
            // Set fixed sender, use reply-to for user email
            $this->mail->setFrom('noreply@company.com', 'Contact Form');
            $this->mail->addReplyTo($email, $safeName);
            $this->mail->addAddress('admin@company.com');
            $this->mail->Subject = 'Contact Form Submission';
            $this->mail->Body = htmlspecialchars($message, ENT_QUOTES, 'UTF-8');

            return $this->mail->send();
        } catch (Exception $e) {
            error_log('Mail error: ' . $e->getMessage());
            return false;
        }
    }

    private function validateEmail(string $email): bool {
        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return false;
        }
        // Additional check for shell metacharacters
        if (preg_match('/[\"\'\\\/\|\;\&\$\`]/', $email)) {
            return false;
        }
        return true;
    }
}
```

**Key Security Controls**:
- **Semantic versioning with caret (^)**: Allows patch updates but prevents breaking changes while getting security fixes
- **roave/security-advisories**: Blocks installation of packages with known vulnerabilities
- **SMTP transport**: Uses authenticated SMTP instead of vulnerable mail() function
- **Fixed sender address**: User email goes in Reply-To, preventing injection in From field

Excellent question! Automated dependency scanning in CI/CD is essential for catching vulnerabilities before they reach production. Here's a comprehensive production-ready setup.

**PRODUCTION PATTERN**:

```php
<?php
// security/DependencyAuditService.php

namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Contracts\HttpClient\HttpClientInterface;

class DependencyAuditService {
    private const SEVERITY_SCORES = [
        'critical' => 4,
        'high' => 3,
        'medium' => 2,
        'low' => 1
    ];

    private const BLOCK_THRESHOLD = 3; // Block on HIGH or CRITICAL

    private LoggerInterface $logger;
    private HttpClientInterface $httpClient;
    private string $composerLockPath;
    private array $allowedVulnerabilities = [];

    public function __construct(
        LoggerInterface $logger,
        HttpClientInterface $httpClient,
        string $projectRoot
    ) {
        $this->logger = $logger;
        $this->httpClient = $httpClient;
        $this->composerLockPath = $projectRoot . '/composer.lock';
        $this->loadAllowList($projectRoot . '/security-allowlist.json');
    }

    public function runAudit(): AuditResult {
        $startTime = microtime(true);

        // Run composer audit
        $composerAudit = $this->runComposerAudit();

        // Cross-reference with external vulnerability databases
        $externalVulns = $this->checkExternalDatabases();

        // Merge and deduplicate findings
        $allVulnerabilities = $this->mergeFindings($composerAudit, $externalVulns);

        // Filter out allowed vulnerabilities (with justification)
        $actionableVulns = $this->filterAllowedVulnerabilities($allVulnerabilities);

        // Calculate risk score
        $riskScore = $this->calculateRiskScore($actionableVulns);

        // Log audit results
        $duration = microtime(true) - $startTime;
        $this->logAuditResults($actionableVulns, $riskScore, $duration);

        return new AuditResult(
            vulnerabilities: $actionableVulns,
            riskScore: $riskScore,
            shouldBlock: $riskScore >= self::BLOCK_THRESHOLD,
            duration: $duration
        );
    }

    private function runComposerAudit(): array {
        $output = [];
        $returnCode = 0;

        exec('composer audit --format=json 2>&1', $output, $returnCode);

        $jsonOutput = implode("\n", $output);
        $result = json_decode($jsonOutput, true);

        if (json_last_error() !== JSON_ERROR_NONE) {
            $this->logger->error('Failed to parse composer audit output', [
                'output' => $jsonOutput,
                'error' => json_last_error_msg()
            ]);
            return [];
        }

        return $result['advisories'] ?? [];
    }

    private function checkExternalDatabases(): array {
        $lockContent = json_decode(file_get_contents($this->composerLockPath), true);
        $packages = [];

        foreach ($lockContent['packages'] ?? [] as $package) {
            $packages[] = [
                'name' => $package['name'],
                'version' => $package['version']
            ];
        }

        // Query OSV (Open Source Vulnerabilities) database
        try {
            $response = $this->httpClient->request('POST', 'https://api.osv.dev/v1/querybatch', [
                'json' => [
                    'queries' => array_map(function($pkg) {
                        return [
                            'package' => [
                                'name' => $pkg['name'],
                                'ecosystem' => 'Packagist'
                            ],
                            'version' => $pkg['version']
                        ];
                    }, $packages)
                ]
            ]);

            return json_decode($response->getContent(), true)['results'] ?? [];
        } catch (\Exception $e) {
            $this->logger->warning('External vulnerability check failed', [
                'error' => $e->getMessage()
            ]);
            return [];
        }
    }

    private function calculateRiskScore(array $vulnerabilities): int {
        $maxScore = 0;

        foreach ($vulnerabilities as $vuln) {
            $severity = strtolower($vuln['severity'] ?? 'unknown');
            $score = self::SEVERITY_SCORES[$severity] ?? 0;
            $maxScore = max($maxScore, $score);
        }

        return $maxScore;
    }

    private function filterAllowedVulnerabilities(array $vulns): array {
        return array_filter($vulns, function($vuln) {
            $cve = $vuln['cve'] ?? $vuln['id'] ?? '';

            if (isset($this->allowedVulnerabilities[$cve])) {
                $allowEntry = $this->allowedVulnerabilities[$cve];

                // Check if allowance has expired
                if (strtotime($allowEntry['expires']) < time()) {
                    $this->logger->warning('Vulnerability allowance expired', [
                        'cve' => $cve,
                        'expired' => $allowEntry['expires']
                    ]);
                    return true; // Include in results (allowance expired)
                }

                $this->logger->info('Vulnerability allowed by policy', [
                    'cve' => $cve,
                    'reason' => $allowEntry['reason'],
                    'approved_by' => $allowEntry['approved_by']
                ]);
                return false; // Exclude from results
            }

            return true; // Include in results
        });
    }

    private function logAuditResults(array $vulns, int $riskScore, float $duration): void {
        $this->logger->info('Dependency audit completed', [
            'vulnerability_count' => count($vulns),
            'risk_score' => $riskScore,
            'should_block' => $riskScore >= self::BLOCK_THRESHOLD,
            'duration_seconds' => round($duration, 3),
            'vulnerabilities' => array_map(function($v) {
                return [
                    'package' => $v['package'] ?? 'unknown',
                    'cve' => $v['cve'] ?? $v['id'] ?? 'unknown',
                    'severity' => $v['severity'] ?? 'unknown'
                ];
            }, $vulns)
        ]);
    }

    private function loadAllowList(string $path): void {
        if (file_exists($path)) {
            $content = json_decode(file_get_contents($path), true);
            $this->allowedVulnerabilities = $content['allowed'] ?? [];
        }
    }
}

class AuditResult {
    public function __construct(
        public readonly array $vulnerabilities,
        public readonly int $riskScore,
        public readonly bool $shouldBlock,
        public readonly float $duration
    ) {}

    public function toJson(): string {
        return json_encode([
            'vulnerability_count' => count($this->vulnerabilities),
            'risk_score' => $this->riskScore,
            'should_block' => $this->shouldBlock,
            'duration' => $this->duration,
            'details' => $this->vulnerabilities
        ], JSON_PRETTY_PRINT);
    }
}
```

**CI/CD Pipeline Configuration (GitHub Actions)**:

```yaml
# .github/workflows/security-scan.yml
name: Security Scan

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 6 * * *'  # Daily at 6 AM UTC

jobs:
  dependency-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup PHP
        uses: shivammathur/setup-php@v2
        with:
          php-version: '8.3'
          tools: composer:v2

      - name: Install dependencies
        run: composer install --no-dev --prefer-dist

      - name: Run Composer Audit
        run: |
          composer audit --format=json > audit-results.json
          cat audit-results.json
        continue-on-error: true

      - name: Run Local PHP Security Checker
        run: |
          curl -sL https://github.com/fabpot/local-php-security-checker/releases/download/v2.0.6/local-php-security-checker_2.0.6_linux_amd64 -o security-checker
          chmod +x security-checker
          ./security-checker --format=json > security-check.json
        continue-on-error: true

      - name: Analyze Results
        run: php bin/console security:analyze-audit

      - name: Upload Security Report
        uses: actions/upload-artifact@v4
        with:
          name: security-report
          path: |
            audit-results.json
            security-check.json

      - name: Notify on Critical Vulnerabilities
        if: failure()
        uses: slackapi/slack-github-action@v1
        with:
          payload: |
            {
              "text": "🚨 Critical vulnerability detected in ${{ github.repository }}",
              "blocks": [
                {
                  "type": "section",
                  "text": {
                    "type": "mrkdwn",
                    "text": "*Security Alert*\nCritical vulnerabilities found in dependencies.\n<${{ github.server_url }}/${{ github.repository }}/actions/runs/${{ github.run_id }}|View Details>"
                  }
                }
              ]
            }
        env:
          SLACK_WEBHOOK_URL: ${{ secrets.SLACK_SECURITY_WEBHOOK }}
```

**Defense in Depth Layers**:

1. **Pre-commit Hook** - Block commits with vulnerable dependencies:
```bash
#!/bin/bash
# .git/hooks/pre-commit
composer audit --locked
if [ $? -ne 0 ]; then
    echo "Vulnerabilities detected. Run 'composer update' to fix."
    exit 1
fi
```

2. **composer.json Configuration** - Enforce security policies:
```json
{
    "require": {
        "php": "^8.2"
    },
    "require-dev": {
        "roave/security-advisories": "dev-latest"
    },
    "config": {
        "audit": {
            "abandoned": "fail"
        },
        "lock": true,
        "preferred-install": "dist",
        "sort-packages": true
    },
    "scripts": {
        "security-check": [
            "@composer audit",
            "./vendor/bin/local-php-security-checker"
        ]
    }
}
```

3. **Runtime Version Verification** - Verify dependencies at startup:
```php
<?php
// bootstrap/security.php

function verifyDependencyIntegrity(): void {
    $lockHash = hash_file('sha256', __DIR__ . '/../composer.lock');
    $expectedHash = getenv('COMPOSER_LOCK_HASH');

    if ($expectedHash && $lockHash !== $expectedHash) {
        error_log('SECURITY ALERT: composer.lock hash mismatch');
        if (getenv('APP_ENV') === 'production') {
            http_response_code(503);
            die('Service temporarily unavailable');
        }
    }
}
```

**Additional Protections**:
- **Dependabot/Renovate**: Automated PRs for dependency updates with security priority
- **SBOM Generation**: Create Software Bill of Materials for compliance (`composer show --format=json`)
- **Version Pinning**: Use exact versions in production (`composer.lock` committed)
- **Vulnerability Database Caching**: Cache vulnerability data to avoid rate limits and ensure availability
- **Graduated Response**: Different thresholds for blocking dev vs production deployments
